export function getEvaluationData(tileId: string | null): EvaluationPayload | null { switch (tileId) {
case 'faq-knowledge': return { overview: faqOverview, scenarios: faqScenarios, coverageGaps: faqCoverageGaps, decisionPaths: faqDecisionPaths };
case 'doc-intelligence': return { overview: docOverview, scenarios: docScenarios, coverageGaps: docCoverageGaps, decisionPaths: docDecisionPaths };
case 'research-comparison': return { overview: researchOverview, scenarios: researchScenarios, coverageGaps: researchCoverageGaps, decisionPaths: researchDecisionPaths };
case 'decision-workflow': return { overview: dentalOverview, scenarios: dentalScenarios, coverageGaps: dentalCoverageGaps, decisionPaths: dentalDecisionPaths };
case 'saas-copilot': return { overview: saasOverview, scenarios: saasScenarios, coverageGaps: saasCoverageGaps, decisionPaths: saasDecisionPaths };
case 'ops-agent': return { overview: opsOverview, scenarios: opsScenarios, coverageGaps: opsCoverageGaps, decisionPaths: opsDecisionPaths };
case 'coding-agent': return { overview: codingOverview, scenarios: codingScenarios, coverageGaps: codingCoverageGaps, decisionPaths: codingDecisionPaths };
case 'onprem-assistant': return { overview: onpremOverview, scenarios: onpremScenarios, coverageGaps: onpremCoverageGaps, decisionPaths: onpremDecisionPaths };
case 'multimodal-agent': return { overview: multimodalOverview, scenarios: multimodalScenarios, coverageGaps: multimodalCoverageGaps, decisionPaths: multimodalDecisionPaths };
case 'consumer-chat': return { overview: consumerOverview, scenarios: consumerScenarios, coverageGaps: consumerCoverageGaps, decisionPaths: consumerDecisionPaths };
default: return null } }
